# TestResultsAggregator
# Parses JUnit XML and JSON test result files, aggregates across multiple runs
# (matrix builds), detects flaky tests, and renders a markdown summary that
# can be dropped into $GITHUB_STEP_SUMMARY.
#
# Each test case is represented as a PSCustomObject with shape:
#   Name             string  - test name (classname.name for JUnit)
#   Status           string  - 'Passed' | 'Failed' | 'Skipped'
#   DurationSeconds  double  - duration in seconds
#   RunName          string  - which input file/run produced this case
#   Message          string  - failure/skip message (optional)

Set-StrictMode -Version Latest

function Read-JUnitTestResult {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Path,
        [string] $RunName
    )

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "JUnit file not found: $Path"
    }
    if (-not $RunName) { $RunName = [System.IO.Path]::GetFileNameWithoutExtension($Path) }

    try {
        [xml]$xml = Get-Content -LiteralPath $Path -Raw
    } catch {
        throw "Failed to parse XML file '$Path': $($_.Exception.Message)"
    }

    # Accept either <testsuites><testsuite>... or a top-level <testsuite>
    $suites = @()
    if ($xml.testsuites) {
        $suites = @($xml.testsuites.testsuite)
    } elseif ($xml.testsuite) {
        $suites = @($xml.testsuite)
    }

    $cases = foreach ($suite in $suites) {
        if (-not $suite) { continue }
        foreach ($tc in @($suite.testcase)) {
            if (-not $tc) { continue }
            $status = 'Passed'
            $message = $null
            if ($tc.failure) { $status = 'Failed'; $message = $tc.failure.message }
            elseif ($tc.error) { $status = 'Failed'; $message = $tc.error.message }
            elseif ($tc.skipped -ne $null) { $status = 'Skipped' }

            $name = if ($tc.classname) { "$($tc.classname).$($tc.name)" } else { $tc.name }
            $duration = 0.0
            if ($tc.time) { [double]::TryParse($tc.time, [ref]$duration) | Out-Null }

            [pscustomobject]@{
                Name            = $name
                Status          = $status
                DurationSeconds = $duration
                RunName         = $RunName
                Message         = $message
            }
        }
    }

    return ,@($cases)
}

function Read-JsonTestResult {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Path,
        [string] $RunName
    )

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "JSON file not found: $Path"
    }
    if (-not $RunName) { $RunName = [System.IO.Path]::GetFileNameWithoutExtension($Path) }

    try {
        $data = Get-Content -LiteralPath $Path -Raw | ConvertFrom-Json
    } catch {
        throw "Failed to parse JSON file '$Path': $($_.Exception.Message)"
    }

    # Accept either { tests: [...] } or a top-level array
    $rawTests = if ($data -is [System.Array]) { $data }
                elseif ($data.PSObject.Properties.Name -contains 'tests') { $data.tests }
                else { @($data) }

    $cases = foreach ($t in $rawTests) {
        $statusRaw = if ($t.PSObject.Properties.Name -contains 'status') { "$($t.status)" } else { 'passed' }
        $status = switch -Regex ($statusRaw.ToLowerInvariant()) {
            '^pass'   { 'Passed';  break }
            '^fail'   { 'Failed';  break }
            '^skip'   { 'Skipped'; break }
            '^error'  { 'Failed';  break }
            default   { 'Passed' }
        }
        $duration = 0.0
        if ($t.PSObject.Properties.Name -contains 'duration_ms' -and $t.duration_ms) {
            $duration = [double]$t.duration_ms / 1000.0
        } elseif ($t.PSObject.Properties.Name -contains 'duration_seconds' -and $t.duration_seconds) {
            $duration = [double]$t.duration_seconds
        }
        $message = if ($t.PSObject.Properties.Name -contains 'message') { $t.message } else { $null }

        [pscustomobject]@{
            Name            = "$($t.name)"
            Status          = $status
            DurationSeconds = $duration
            RunName         = $RunName
            Message         = $message
        }
    }

    return ,@($cases)
}

function Read-TestResultDirectory {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Path
    )

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "Input directory not found: $Path"
    }

    $all = @()
    $files = Get-ChildItem -LiteralPath $Path -File | Sort-Object Name
    foreach ($f in $files) {
        $runName = [System.IO.Path]::GetFileNameWithoutExtension($f.Name)
        switch -Regex ($f.Extension.ToLowerInvariant()) {
            '\.xml$'  { $all += Read-JUnitTestResult -Path $f.FullName -RunName $runName }
            '\.json$' { $all += Read-JsonTestResult  -Path $f.FullName -RunName $runName }
            default   { Write-Verbose "Skipping unrecognized file: $($f.Name)" }
        }
    }
    return ,@($all)
}

function Get-TestResultSummary {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )
    $passed   = @($Cases | Where-Object Status -eq 'Passed').Count
    $failed   = @($Cases | Where-Object Status -eq 'Failed').Count
    $skipped  = @($Cases | Where-Object Status -eq 'Skipped').Count
    $total    = $Cases.Count
    $duration = ($Cases | Measure-Object -Property DurationSeconds -Sum).Sum
    if (-not $duration) { $duration = 0.0 }

    [pscustomobject]@{
        Total           = $total
        Passed          = $passed
        Failed          = $failed
        Skipped         = $skipped
        DurationSeconds = [math]::Round([double]$duration, 3)
    }
}

function Find-FlakyTest {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )

    $flaky = foreach ($group in ($Cases | Group-Object Name)) {
        $statuses = $group.Group | Select-Object -ExpandProperty Status -Unique
        # Flaky = appeared as Passed in at least one run AND Failed in at least one run.
        if (($statuses -contains 'Passed') -and ($statuses -contains 'Failed')) {
            $passCount = @($group.Group | Where-Object Status -eq 'Passed').Count
            $failCount = @($group.Group | Where-Object Status -eq 'Failed').Count
            [pscustomobject]@{
                Name     = $group.Name
                Runs     = $group.Count
                Passed   = $passCount
                Failed   = $failCount
            }
        }
    }
    return ,@($flaky)
}

function Format-TestSummaryMarkdown {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )

    $summary = Get-TestResultSummary -Cases $Cases
    $flaky   = Find-FlakyTest -Cases $Cases
    $failed  = @($Cases | Where-Object Status -eq 'Failed')

    $sb = [System.Text.StringBuilder]::new()
    [void]$sb.AppendLine('# Test Results')
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('## Totals')
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine("- Total: $($summary.Total)")
    [void]$sb.AppendLine("- Passed: $($summary.Passed)")
    [void]$sb.AppendLine("- Failed: $($summary.Failed)")
    [void]$sb.AppendLine("- Skipped: $($summary.Skipped)")
    [void]$sb.AppendLine("- Duration: $($summary.DurationSeconds)s")
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('## Flaky Tests')
    [void]$sb.AppendLine('')
    if ($flaky.Count -gt 0) {
        [void]$sb.AppendLine('| Test | Runs | Passed | Failed |')
        [void]$sb.AppendLine('| --- | --- | --- | --- |')
        foreach ($f in $flaky) {
            [void]$sb.AppendLine("| $($f.Name) | $($f.Runs) | $($f.Passed) | $($f.Failed) |")
        }
    } else {
        [void]$sb.AppendLine('No flaky tests detected.')
    }
    [void]$sb.AppendLine('')
