        $message = $null
        if ($failure) { $status = 'Failed';  $message = $failure.GetAttribute('message') }
        elseif ($errorN) { $status = 'Failed'; $message = $errorN.GetAttribute('message') }
        elseif ($skipped) { $status = 'Skipped'; $message = $skipped.GetAttribute('message') }

        # Use the bare test name as the identity for cross-run flaky detection;
        # classname is preserved separately for context.
        $className = $tc.GetAttribute('classname')
        $name      = $tc.GetAttribute('name')

        $duration = 0.0
        $timeAttr = $tc.GetAttribute('time')
        if ($timeAttr) { [double]::TryParse($timeAttr, [ref]$duration) | Out-Null }

        $cases.Add([pscustomobject]@{
            Name            = $name
            Status          = $status
            DurationSeconds = $duration
            RunName         = $RunName
            Message         = $message
        })
    }

    return ,$cases.ToArray()
}

function Read-JsonTestResult {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Path,
        [string] $RunName
    )

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "JSON file not found: $Path"
    }
    if (-not $RunName) { $RunName = [System.IO.Path]::GetFileNameWithoutExtension($Path) }

    try {
        $data = Get-Content -LiteralPath $Path -Raw | ConvertFrom-Json
    } catch {
        throw "Failed to parse JSON file '$Path': $($_.Exception.Message)"
    }

    # Accept either { tests: [...] } or a top-level array.
    $rawTests = @()
    if ($data -is [System.Array]) {
        $rawTests = $data
    } elseif ($data.PSObject.Properties.Name -contains 'tests') {
        $rawTests = @($data.tests)
    } else {
        $rawTests = @($data)
    }

    $cases = [System.Collections.Generic.List[object]]::new()
    foreach ($t in $rawTests) {
        $props = $t.PSObject.Properties.Name
        $statusRaw = if ($props -contains 'status') { "$($t.status)" } else { 'passed' }
        $status = switch -Regex ($statusRaw.ToLowerInvariant()) {
            '^pass'  { 'Passed';  break }
            '^fail'  { 'Failed';  break }
            '^skip'  { 'Skipped'; break }
            '^error' { 'Failed';  break }
            default  { 'Passed' }
        }

        $duration = 0.0
        if ($props -contains 'duration_ms' -and $t.duration_ms) {
            $duration = [double]$t.duration_ms / 1000.0
        } elseif ($props -contains 'duration_seconds' -and $t.duration_seconds) {
            $duration = [double]$t.duration_seconds
        } elseif ($props -contains 'duration' -and $t.duration) {
            $duration = [double]$t.duration
        }

        $message = if ($props -contains 'message') { "$($t.message)" } else { $null }

        $cases.Add([pscustomobject]@{
            Name            = "$($t.name)"
            Status          = $status
            DurationSeconds = $duration
            RunName         = $RunName
            Message         = $message
        })
    }

    return ,$cases.ToArray()
}

function Read-TestResultDirectory {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Path
    )

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "Input directory not found: $Path"
    }

    $all = [System.Collections.Generic.List[object]]::new()
    $files = Get-ChildItem -LiteralPath $Path -File | Sort-Object Name
    foreach ($f in $files) {
        $runName = [System.IO.Path]::GetFileNameWithoutExtension($f.Name)
        switch -Regex ($f.Extension.ToLowerInvariant()) {
            '\.xml$'  { foreach ($c in (Read-JUnitTestResult -Path $f.FullName -RunName $runName)) { $all.Add($c) } }
            '\.json$' { foreach ($c in (Read-JsonTestResult  -Path $f.FullName -RunName $runName)) { $all.Add($c) } }
            default   { Write-Verbose "Skipping unrecognized file: $($f.Name)" }
        }
    }
    return ,$all.ToArray()
}

function Get-TestResultSummary {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )
    $passed   = @($Cases | Where-Object { $_.Status -eq 'Passed' }).Count
    $failed   = @($Cases | Where-Object { $_.Status -eq 'Failed' }).Count
    $skipped  = @($Cases | Where-Object { $_.Status -eq 'Skipped' }).Count
    $duration = ($Cases | Measure-Object -Property DurationSeconds -Sum).Sum
    if (-not $duration) { $duration = 0.0 }

    [pscustomobject]@{
        Total           = $Cases.Count
        Passed          = $passed
        Failed          = $failed
        Skipped         = $skipped
        DurationSeconds = [math]::Round([double]$duration, 3)
    }
}

function Find-FlakyTest {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )

    $flaky = [System.Collections.Generic.List[object]]::new()
    foreach ($group in ($Cases | Group-Object Name)) {
        $statuses = @($group.Group | Select-Object -ExpandProperty Status -Unique)
        # Flaky = test appeared as Passed in at least one run AND Failed in at least one run.
        if (($statuses -contains 'Passed') -and ($statuses -contains 'Failed')) {
            $passCount = @($group.Group | Where-Object { $_.Status -eq 'Passed' }).Count
            $failCount = @($group.Group | Where-Object { $_.Status -eq 'Failed' }).Count
            $flaky.Add([pscustomobject]@{
                Name   = $group.Name
                Runs   = $group.Count
                Passed = $passCount
                Failed = $failCount
            })
        }
    }
    return ,$flaky.ToArray()
}

function Format-TestSummaryMarkdown {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [object[]] $Cases
    )

    $summary = Get-TestResultSummary -Cases $Cases
    $flaky   = Find-FlakyTest -Cases $Cases
    $failed  = @($Cases | Where-Object { $_.Status -eq 'Failed' })

    $sb = [System.Text.StringBuilder]::new()
    [void]$sb.AppendLine('# Test Results')
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('## Totals')
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine("- Total: $($summary.Total)")
    [void]$sb.AppendLine("- Passed: $($summary.Passed)")
    [void]$sb.AppendLine("- Failed: $($summary.Failed)")
    [void]$sb.AppendLine("- Skipped: $($summary.Skipped)")
    [void]$sb.AppendLine("- Duration: $($summary.DurationSeconds)s")
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('## Flaky Tests')
    [void]$sb.AppendLine('')
    if ($flaky.Count -gt 0) {
        [void]$sb.AppendLine('| Test | Runs | Passed | Failed |')
        [void]$sb.AppendLine('| --- | --- | --- | --- |')
        foreach ($f in $flaky) {
            [void]$sb.AppendLine("| $($f.Name) | $($f.Runs) | $($f.Passed) | $($f.Failed) |")
        }
    } else {
        [void]$sb.AppendLine('No flaky tests detected.')
    }
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('## Failures')
    [void]$sb.AppendLine('')
    if ($failed.Count -gt 0) {
        [void]$sb.AppendLine('| Test | Run | Message |')
        [void]$sb.AppendLine('| --- | --- | --- |')
        foreach ($c in $failed) {
            $msgRaw = if ($c.PSObject.Properties.Name -contains 'Message') { "$($c.Message)" } else { '' }
            $msg = ($msgRaw -replace '\r?\n', ' ').Trim()
            if (-not $msg) { $msg = '(no message)' }
            [void]$sb.AppendLine("| $($c.Name) | $($c.RunName) | $msg |")
        }
    } else {
        [void]$sb.AppendLine('No failures.')
    }
    return $sb.ToString()
}

function Invoke-TestResultsAggregator {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $InputDirectory,
        [Parameter(Mandatory)] [string] $OutputPath
    )

    $cases = Read-TestResultDirectory -Path $InputDirectory
    if ($cases.Count -eq 0) {
        throw "No recognized test result files (.xml or .json) found in '$InputDirectory'."
    }
    $md = Format-TestSummaryMarkdown -Cases $cases
    $outDir = Split-Path -Parent $OutputPath
    if ($outDir -and -not (Test-Path -LiteralPath $outDir)) {
        New-Item -ItemType Directory -Path $outDir -Force | Out-Null
    }
    Set-Content -LiteralPath $OutputPath -Value $md -Encoding UTF8
    return Get-TestResultSummary -Cases $cases
}

Export-ModuleMember -Function `
    Read-JUnitTestResult, Read-JsonTestResult, Read-TestResultDirectory, `
    Get-TestResultSummary, Find-FlakyTest, Format-TestSummaryMarkdown, `
    Invoke-TestResultsAggregator

# Pester tests for TestResultsAggregator. TDD style.
# Each Describe block was added by writing the failing test first,
# then the minimum implementation to pass.

BeforeAll {
    $script:ModulePath = Join-Path $PSScriptRoot '..' 'src' 'TestResultsAggregator.psm1'
    Import-Module $script:ModulePath -Force
    $script:FixturesDir = Join-Path $PSScriptRoot 'fixtures'
}

Describe 'Read-JUnitTestResult' {
    It 'parses a JUnit XML file into structured test cases' {
        $path = Join-Path $script:FixturesDir 'junit-run1.xml'
        $cases = Read-JUnitTestResult -Path $path
        $cases.Count | Should -Be 4
        ($cases | Where-Object Name -eq 'test_login').Status | Should -Be 'Passed'
        ($cases | Where-Object Name -eq 'test_logout').Status | Should -Be 'Failed'
        ($cases | Where-Object Name -eq 'test_skipped_feature').Status | Should -Be 'Skipped'
        # Duration parsed to seconds (double)
        ($cases | Where-Object Name -eq 'test_login').DurationSeconds | Should -BeGreaterThan 0
    }

    It 'throws a meaningful error for a missing file' {
        { Read-JUnitTestResult -Path '/nonexistent/path.xml' } |
            Should -Throw -ExpectedMessage '*not found*'
    }

    It 'throws a meaningful error for a malformed XML file' {
        $tmp = New-TemporaryFile
        Set-Content -Path $tmp -Value '<not-valid-xml'
        try {
            { Read-JUnitTestResult -Path $tmp } |
                Should -Throw -ExpectedMessage '*XML*'
        } finally {
            Remove-Item $tmp -Force
        }
    }
}

Describe 'Read-JsonTestResult' {
    It 'parses a JSON test results file into structured test cases' {
        $path = Join-Path $script:FixturesDir 'results-run1.json'
        $cases = Read-JsonTestResult -Path $path
        $cases.Count | Should -BeGreaterThan 0
        $cases[0].PSObject.Properties.Name | Should -Contain 'Name'
        $cases[0].PSObject.Properties.Name | Should -Contain 'Status'
        $cases[0].PSObject.Properties.Name | Should -Contain 'DurationSeconds'
    }

    It 'throws for a missing file' {
        { Read-JsonTestResult -Path '/nonexistent/path.json' } |
            Should -Throw -ExpectedMessage '*not found*'
    }
}

Describe 'Read-TestResultDirectory' {
    It 'auto-detects JUnit XML and JSON files in a directory and tags them with the run name' {
        $cases = Read-TestResultDirectory -Path $script:FixturesDir
        # Each case should carry the source file basename as RunName
        ($cases | Select-Object -ExpandProperty RunName -Unique).Count | Should -BeGreaterThan 1
    }
}

Describe 'Get-TestResultSummary' {
    It 'computes totals across all test cases' {
        $cases = @(
            [pscustomobject]@{ Name='a'; Status='Passed';  DurationSeconds=1.0; RunName='r1' }
            [pscustomobject]@{ Name='b'; Status='Failed';  DurationSeconds=2.0; RunName='r1' }
            [pscustomobject]@{ Name='c'; Status='Skipped'; DurationSeconds=0.0; RunName='r1' }
            [pscustomobject]@{ Name='d'; Status='Passed';  DurationSeconds=1.5; RunName='r2' }
        )
        $s = Get-TestResultSummary -Cases $cases
        $s.Total           | Should -Be 4
        $s.Passed          | Should -Be 2
        $s.Failed          | Should -Be 1
        $s.Skipped         | Should -Be 1
        $s.DurationSeconds | Should -Be 4.5
    }
}

Describe 'Find-FlakyTest' {
    It 'identifies tests that passed in some runs but failed in others' {
        $cases = @(
            [pscustomobject]@{ Name='stable_pass'; Status='Passed'; RunName='r1' }
            [pscustomobject]@{ Name='stable_pass'; Status='Passed'; RunName='r2' }
            [pscustomobject]@{ Name='flaky';       Status='Passed'; RunName='r1' }
            [pscustomobject]@{ Name='flaky';       Status='Failed'; RunName='r2' }
            [pscustomobject]@{ Name='always_fail'; Status='Failed'; RunName='r1' }
            [pscustomobject]@{ Name='always_fail'; Status='Failed'; RunName='r2' }
        )
        $flaky = Find-FlakyTest -Cases $cases
        $flaky.Count | Should -Be 1
        $flaky[0].Name | Should -Be 'flaky'
    }

    It 'returns an empty array if there are no flaky tests' {
        $cases = @(
            [pscustomobject]@{ Name='a'; Status='Passed'; RunName='r1' }
            [pscustomobject]@{ Name='a'; Status='Passed'; RunName='r2' }
        )
        $flaky = @(Find-FlakyTest -Cases $cases)
        $flaky.Count | Should -Be 0
    }
}

Describe 'Format-TestSummaryMarkdown' {
    It 'renders a markdown summary suitable for GitHub Actions' {
        $cases = @(
            [pscustomobject]@{ Name='a'; Status='Passed'; DurationSeconds=1.0; RunName='r1' }
            [pscustomobject]@{ Name='a'; Status='Failed'; DurationSeconds=1.1; RunName='r2' }
            [pscustomobject]@{ Name='b'; Status='Failed'; DurationSeconds=0.5; RunName='r1' }
        )
        $md = Format-TestSummaryMarkdown -Cases $cases
        $md | Should -Match '# Test Results'
        $md | Should -Match 'Passed'
        $md | Should -Match 'Failed'
        $md | Should -Match 'Flaky'
        $md | Should -Match '\| a \|'   # flaky test row
    }

    It 'shows a no-flaky-tests note when none are flaky' {
        $cases = @(
            [pscustomobject]@{ Name='a'; Status='Passed'; DurationSeconds=1.0; RunName='r1' }
        )
        $md = Format-TestSummaryMarkdown -Cases $cases
        $md | Should -Match 'No flaky tests'
    }
}

Describe 'Invoke-TestResultsAggregator (end-to-end)' {
    It 'aggregates a directory of fixtures and writes markdown to the output path' {
        $out = Join-Path ([System.IO.Path]::GetTempPath()) "summary-$([guid]::NewGuid()).md"
        try {
            Invoke-TestResultsAggregator -InputDirectory $script:FixturesDir -OutputPath $out | Out-Null
            Test-Path $out | Should -BeTrue
            $md = Get-Content $out -Raw
            $md | Should -Match '# Test Results'
            $md | Should -Match 'Total:'
        } finally {
            if (Test-Path $out) { Remove-Item $out -Force }
        }
    }
}

